module serial2parallel
(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg dout_parallel,
    output reg dout_valid
);

reg [2:0] counter;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        dout_parallel <= 8'b0;
        dout_valid <= 1'b0;
        counter <= 3'b0;
    end
    else if (din_valid) begin
        if (counter == 3'b111) begin
            dout_parallel <= {din_serial, dout_parallel[7:1]};
            dout_valid <= 1'b1;
            counter <= 3'b0;
        end
        else begin
            dout_parallel <= {din_serial, dout_parallel[7:1]};
            dout_valid <= 1'b0;
            counter <= counter + 1'b1;
        end
    end
    else begin
        dout_valid <= 1'b0;
    end
end

endmodule
